INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Language: Prefer English + Spanish', '(?i)^(?:(?=.*(?:\beng(?:lish)?\b|\btrueenglish\b|\bingles\b|\bingl[e\u00e9]s\b|[._ \-\[\(](?:en|eng|enus)[._ \-\]\)]))(?=.*(?:(?:\bspa(?:nish)?\b|\besp(?:anol|a\u00f1ol)?\b|\bespanol\b|\bespa\u00f1ol\b|\bcastellano\b|\bcastilian\b)|(?:\blatino\b|\blatina\b|\blatam\b|\blatin[ ._-]?america(?:n)?\b|\blatinoamerica(?:no)?\b|\blatinoam[e\u00e9]rica(?:no)?\b|\bespa[n\u00f1]ol[ ._-]?latino\b|\blat(?:ino)?[ ._-]?dub(?:bed)?\b|\baudio[ ._-]?(?:latino|latam|spanish|espa[n\u00f1]ol)\b|\bcast(?:ellano)?\b|\bmex(?:ican|ico)?\b|\bmx\b|\bes[ ._-]?(?:la|lat|419|mx|es|us)\b|\bspa[ ._-]?(?:lat|la|mx|cast|es|419)\b|\besp[ ._-]?(?:lat|la|mx|cast|es|419)\b|[._ \-\[\(](?:es|spa|esp|lat|la|mx|es419)[._ \-\]\)])))|(?=.*(?:\blatino\b|\blatina\b|\blatam\b|\blatin[ ._-]?america(?:n)?\b|\blatinoamerica(?:no)?\b|\blatinoam[e\u00e9]rica(?:no)?\b|\bespa[n\u00f1]ol[ ._-]?latino\b|\blat(?:ino)?[ ._-]?dub(?:bed)?\b|\baudio[ ._-]?(?:latino|latam|spanish|espa[n\u00f1]ol)\b|\bcast(?:ellano)?\b|\bmex(?:ican|ico)?\b|\bmx\b|\bes[ ._-]?(?:la|lat|419|mx|es|us)\b|\bspa[ ._-]?(?:lat|la|mx|cast|es|419)\b|\besp[ ._-]?(?:lat|la|mx|cast|es|419)\b|[._ \-\[\(](?:es|spa|esp|lat|la|mx|es419)[._ \-\]\)]))(?=.*(?:\bmulti(?:[ ._-]?(?:audio|lang|language|dub|sub|subs))?\b|\bmulti\d+\b|\bmultilang\b|\bmultiaudio\b|\bdual[ ._-]?(?:audio|lang(?:uage)?|dub)?\b|\btri[ ._-]?audio\b|\bdualaudio\b|\bdual\b))|(?=.*(?:\beng(?:lish)?\b|\btrueenglish\b|\bingles\b|\bingl[e\u00e9]s\b|[._ \-\[\(](?:en|eng|enus)[._ \-\]\)]))(?=.*(?:\blatino\b|\blatina\b|\blatam\b|\blatin[ ._-]?america(?:n)?\b|\blatinoamerica(?:no)?\b|\blatinoam[e\u00e9]rica(?:no)?\b|\bespa[n\u00f1]ol[ ._-]?latino\b|\blat(?:ino)?[ ._-]?dub(?:bed)?\b|\baudio[ ._-]?(?:latino|latam|spanish|espa[n\u00f1]ol)\b|\bcast(?:ellano)?\b|\bmex(?:ican|ico)?\b|\bmx\b|\bes[ ._-]?(?:la|lat|419|mx|es|us)\b|\bspa[ ._-]?(?:lat|la|mx|cast|es|419)\b|\besp[ ._-]?(?:lat|la|mx|cast|es|419)\b|[._ \-\[\(](?:es|spa|esp|lat|la|mx|es419)[._ \-\]\)]))).*$', 'Highest language preference. Rewards releases that appear to include both English and Spanish/Latino language indicators, or a strong Latino/multi-audio signal, so Plex gets the best bilingual copy first.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Language: Prefer English + Spanish', 'Language');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Language: English Marker', '(?i)(?:\beng(?:lish)?\b|\btrueenglish\b|\bingles\b|\bingl[e\u00e9]s\b|[._ \-\[\(](?:en|eng|enus)[._ \-\]\)])', 'Tiny English-tag confirmation bonus. English is treated as the last language fallback, so this exists mainly to confirm the tag rather than drive the decision.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Language: English Marker', 'Language');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Language: Spanish-Only Fallback', '(?i)^(?=.*(?:\bspa(?:nish)?\b|\besp(?:anol|a\u00f1ol)?\b|\bespanol\b|\bespa\u00f1ol\b|\bcastellano\b|\bcastilian\b))(?!.*(?:\beng(?:lish)?\b|\btrueenglish\b|\bingles\b|\bingl[e\u00e9]s\b|[._ \-\[\(](?:en|eng|enus)[._ \-\]\)]))(?!.*(?:\bmulti(?:[ ._-]?(?:audio|lang|language|dub|sub|subs))?\b|\bmulti\d+\b|\bmultilang\b|\bmultiaudio\b|\bdual[ ._-]?(?:audio|lang(?:uage)?|dub)?\b|\btri[ ._-]?audio\b|\bdualaudio\b|\bdual\b)).*$', 'Preferred single-language fallback. Rewards explicit Spanish or Castellano tags when a true bilingual English+Spanish release is not available.');
