INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Language: Latino Spanish Fallback', '(?i)^(?=.*(?:\blatino\b|\blatina\b|\blatam\b|\blatin[ ._-]?america(?:n)?\b|\blatinoamerica(?:no)?\b|\blatinoam[e\u00e9]rica(?:no)?\b|\bespa[n\u00f1]ol[ ._-]?latino\b|\blat(?:ino)?[ ._-]?dub(?:bed)?\b|\baudio[ ._-]?(?:latino|latam|spanish|espa[n\u00f1]ol)\b|\bcast(?:ellano)?\b|\bmex(?:ican|ico)?\b|\bmx\b|\bes[ ._-]?(?:la|lat|419|mx|es|us)\b|\bspa[ ._-]?(?:lat|la|mx|cast|es|419)\b|\besp[ ._-]?(?:lat|la|mx|cast|es|419)\b|[._ \-\[\(](?:es|spa|esp|lat|la|mx|es419)[._ \-\]\)]))(?!.*(?:\bspa(?:nish)?\b|\besp(?:anol|a\u00f1ol)?\b|\bespanol\b|\bespa\u00f1ol\b|\bcastellano\b|\bcastilian\b))(?!.*(?:\beng(?:lish)?\b|\btrueenglish\b|\bingles\b|\bingl[e\u00e9]s\b|[._ \-\[\(](?:en|eng|enus)[._ \-\]\)]))(?!.*(?:\bmulti(?:[ ._-]?(?:audio|lang|language|dub|sub|subs))?\b|\bmulti\d+\b|\bmultilang\b|\bmultiaudio\b|\bdual[ ._-]?(?:audio|lang(?:uage)?|dub)?\b|\btri[ ._-]?audio\b|\bdualaudio\b|\bdual\b)).*$', 'Secondary Spanish-friendly fallback for Latino, LATAM, Mexican, or ES-style tags that often imply Spanish audio even when English is not clearly labeled.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Language: Latino Spanish Fallback', 'Language');
