INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Language: Block Other Languages', '(?i)(?:\b(?:(?:480p|576p|720p|1080p|2160p|4k|uhd|bluray|blu[ ._-]?ray|web[ ._-]?dl|webdl|webrip|web[ ._-]?rip|hdrip|hdtv|bdrip|bd[ ._-]?rip|dvdrip|dvd[ ._-]?rip|remux|xvid|avc|x264|h264|h[ ._-]?264|x265|h265|h[ ._-]?265|hevc|av1|vvc|x266|h266|h[ ._-]?266|hdr|hdr10|hdr10plus|hdr10\+|dv|dovi|dts|ddp|eac3|ac3|aac|atmos|proper|repack|rerip))\b(?:.*[._ \-\[\(])(?:(?:truefrench|french|fre|fra|german|ger|deu|italian|ita|portuguese|por|brazilian|russian|rus|japanese|jpn|korean|kor|chinese|chi|zho|mandarin|cantonese|hindi|hin|tamil|telugu|turkish|tur|polish|pol|dutch|nld|swedish|swe|norwegian|nor|danish|dan|finnish|fin|arabic|ara))(?=[._ \-\]\)]|$)|\b(?:audio|dubbed?|dubs?|lang(?:uage)?|vo|vost(?:fr)?|sub(?:s|titles)?)[ ._:-]+(?:(?:truefrench|french|fre|fra|german|ger|deu|italian|ita|portuguese|por|brazilian|russian|rus|japanese|jpn|korean|kor|chinese|chi|zho|mandarin|cantonese|hindi|hin|tamil|telugu|turkish|tur|polish|pol|dutch|nld|swedish|swe|norwegian|nor|danish|dan|finnish|fin|arabic|ara))\b|\b(?:(?:truefrench|french|fre|fra|german|ger|deu|italian|ita|portuguese|por|brazilian|russian|rus|japanese|jpn|korean|kor|chinese|chi|zho|mandarin|cantonese|hindi|hin|tamil|telugu|turkish|tur|polish|pol|dutch|nld|swedish|swe|norwegian|nor|danish|dan|finnish|fin|arabic|ara))[ ._:-]+(?:audio|dubbed?|dubs?|lang(?:uage)?|vo|sub(?:s|titles)?)\b)', 'Heavy negative score for releases tagged as languages outside the intended English or Spanish-friendly target set, such as French, German, Hindi, Russian, Japanese, and similar tags.');
