INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Codec: HEVC-x265 Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Codec: x264-H264 Fallback or Penalty', '(?i)\b(?:avc|[xh][ ._-]?264)\b', 'Compatibility codec detector. In the smart movie profiles this is now a strong negative safety rail so x264 cannot replace an existing x265/AV1/VVC or compact 4K release. The looser catalog profile can still use it manually for hard-to-find movies.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Codec: x264-H264 Fallback or Penalty', 'Codec');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Codec: x264-H264 Fallback or Penalty', 'Blocking');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Codec: x264-H264 Fallback or Penalty', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Source: Block Remux-Raw Disk', '(?i)\b(?:remux|bdremux|blu[ ._-]?ray[ ._-]?remux|br[ ._-]?disk|bd[ ._-]?disk|bdrip[ ._-]?remux|raw[ ._-]?hd)\b', 'Heavy negative score for remux, BD remux, BR-DISK, BD-DISK, and raw HD style releases. Keeps the library from grabbing huge source-size files.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Source: Block Remux-Raw Disk', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Base HDR Bonus', '(?i)(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+)', 'Base HDR bonus. Keeps HDR above SDR, while still letting the more specific Dolby Vision plus HDR and HDR10+ combinations rise higher.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Base HDR Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Base HDR Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: HDR10 Bonus', '(?i)\bhdr10\b(?!\+)', 'Extra HDR score for HDR10. This sits above generic HDR but below Dolby Vision paired with HDR and below HDR10+.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10 Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10 Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: HDR10+ Bonus', '(?i)(?:\bhdr10plus\b|\bhdr10\+)', 'Top non-Dolby-Vision HDR bonus for HDR10+ and HDR10 Plus tags. Combined with Dolby Vision, this becomes the strongest HDR path.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10+ Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10+ Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Dolby Vision + HDR Bonus', '(?i)^(?=.*\b(?:dovi|dolby[ ._-]?vision|dv)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+)).*$', 'Rewards Dolby Vision only when HDR, HDR10, or HDR10+ is also present. This builds the preferred Dolby Vision plus HDR ladders without overvaluing DV-only releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision + HDR Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision + HDR Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Penalize SDR When HDR Expected', '(?i)^(?=.*\b(?:1080p|2160p|4k|uhd)\b)(?=.*\b(?:x265|h[ ._-]?265|hevc|av1|x266|h[ ._-]?266|vvc)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision)).*$', 'Visual-protection penalty for efficient-codec 1080p/2160p releases that do not advertise HDR, HDR10, HDR10+, DoVi, DV, or Dolby Vision. Movies use this strongly to stop SDR replacing HDR; Sonarr uses a lighter version because HDR is less common on shows.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Penalize SDR When HDR Expected', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Gate: Block Missing HDR', '(?i)^(?=.*\b(?:2160p|4k)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision)).*$', 'Managed Smart Plex custom format. Matches release-title tokens and applies the profile score assigned in each curated quality profile.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing HDR', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing HDR', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Dolby Vision Only Fallback', '(?i)^(?=.*\b(?:dovi|dolby[ ._-]?vision|dv)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+)).*$', 'Small Dolby Vision-only fallback score. DV-only releases stay above SDR when necessary, but below every Dolby Vision plus HDR combination.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision Only Fallback', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision Only Fallback', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: 5.1 Surround Preferred', '(?i)\b(?:5[ ._-]?1|6ch|5\.1ch)\b', 'Primary surround-audio bonus for 5.1, 6-channel, and 5.1ch tags. This is the main compatibility target for a Plex setup built around a 5.1-capable soundbar.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 5.1 Surround Preferred', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 5.1 Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Atmos Bonus', '(?i)\b(?:dolby[ ._-]?atmos|ddp[ ._-]?atmos|ec3[ ._-]?joc|atmos)\b', 'Top audio bonus for Dolby Atmos, DDP Atmos, EC3 JOC, and Atmos tags. Atmos is preferred when available because it still rides on a practical Dolby Digital Plus playback path.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Atmos Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Atmos Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: EAC3-AC3 Preferred', '(?i)\b(?:eac3|e-ac-3|ddp|dd\+|ac3|ac-3|dolby[ ._-]?digital[ ._-]?plus|dolby[ ._-]?digital)\b', 'Preferred Dolby audio-format bonus for EAC3, DDP, DD+, AC3, and Dolby Digital tags. These formats are highly compatible for Plex, eARC, and streaming-style playback.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: EAC3-AC3 Preferred', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: EAC3-AC3 Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: 6.1 Bonus', '(?i)\b(?:6[ ._-]?1|7ch|6\.1ch)\b', 'Secondary channel-layout bonus for 6.1 audio. It stays below the main 5.1 and Dolby-format preferences, but above 7.1 and stereo in the fallback ladder.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 6.1 Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 6.1 Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: 7.1 Bonus', '(?i)\b(?:7[ ._-]?1|8ch|7\.1ch)\b', 'Smaller channel-layout bonus for 7.1 audio. It remains below the 5.1-first compatibility target and below 6.1 in the current managed fallback order.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 7.1 Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 7.1 Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: AAC Fallback Marker', '(?i)\baac\b', 'Lowest acceptable audio-codec lane. AAC remains allowed so weak fallback releases can still download, but it sits behind EAC3, AC3, DDP, and Atmos once those exist.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: AAC Fallback Marker', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: AAC Fallback Marker', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Stereo-2.0 Penalty', '(?i)\b(?:1[ ._-]?0|2[ ._-]?(?:0|1)|1ch|2ch|1\.0ch|2\.0ch|2\.1ch|stereo|mono|dual[ ._-]?mono)\b', 'Bottom audio floor for stereo-style tags such as 2.0, 2.1, stereo, mono, and dual mono. These releases stay allowed at the minimum acceptable floor, while surround formats score higher.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Stereo-2.0 Penalty', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Stereo-2.0 Penalty', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Lossless Size Penalty', '(?i)\b(?:truehd|true[ ._-]?hd|dts[ ._-]?hd|dts[ ._-]?ma|dts[ ._-]?hd[ ._-]?ma|flac|pcm|lpcm)\b', 'Small space-awareness penalty for TrueHD, DTS-HD MA, FLAC, PCM, and LPCM. It is not a hard block, but it keeps practical EAC3/AC3 5.1 releases from losing to larger lossless-audio releases only because of audio size.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Lossless Size Penalty', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Lossless Size Penalty', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: UHD BluRay Source Bonus', '(?i)^(?=.*\b1080p\b)(?=.*\b(?:uhd[ ._-]?blu[ ._-]?ray|uhd[ ._-]?bluray)\b)(?!.*\b(?:2160p|4k)\b).*$', 'Small positive score for 1080p encodes sourced from UHD BluRay. This replaces the old accidental 4K bonus on 1080p UHD-source releases, so they get credit for the cleaner source without being treated as true 4K.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: UHD BluRay Source Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: HDR + Surround Preferred', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision))(?=.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', '1080p-only preference for efficient-codec releases that advertise HDR or Dolby Vision and 5.1+ surround. This gives strong 1080p titles their own clean lane instead of borrowing 4K custom formats.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: HDR + Surround Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: HDR + Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: Efficient Encode Bonus', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b).*$', '1080p-only bonus for efficient codecs such as HEVC/x265, AV1, or VVC/x266. It never matches true 2160p or 4K titles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: Efficient Encode Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: BluRay Preferred', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:blu[ ._-]?ray|bluray)\b).*$', '1080p-only source bonus for BluRay releases. This keeps 1080p BluRay preference separate from the true 4K UHD BluRay preference.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: WEB-DL Preferred', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', '1080p-only source bonus for WEB-DL releases. It helps rank clean 1080p WEB-DL fallbacks without applying any 4K-specific logic.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: WEBRip Source', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', '1080p-only WEBRip source detector. Strict movie profiles can penalize or block it, while relaxed catalog and series profiles can keep it as a weaker fallback without borrowing generic or 4K source formats.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: WEBRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: BDRip Source', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:bd[ ._-]?rip|bdrip)\b).*$', '1080p-only BDRip source detector. It keeps 1080p BDRip handling separate from true BluRay and from 4K source rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: BDRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: HDR + Surround Preferred', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision))(?=.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', '720p-only preference for efficient-codec releases that also advertise HDR/Dolby Vision and surround audio. Used mainly by relaxed catalog-style profiles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: HDR + Surround Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: HDR + Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: Efficient Encode Bonus', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b).*$', '720p-only bonus for efficient codecs such as HEVC/x265, AV1, or VVC/x266. It never matches 1080p or true 4K titles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: Efficient Encode Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: BluRay Preferred', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:blu[ ._-]?ray|bluray)\b).*$', '720p-only BluRay source bonus. Keeps 720p BluRay ranking separate from 1080p and 4K BluRay rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: WEB-DL Preferred', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', '720p-only WEB-DL source bonus for clean lower-resolution fallbacks.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: WEBRip Source', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', '720p-only WEBRip source detector for relaxed catalog fallbacks. It does not apply to 1080p or 4K titles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: WEBRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: BDRip Source', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:bd[ ._-]?rip|bdrip)\b).*$', '720p-only BDRip source detector for older or hard-to-find catalog releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: BDRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('576p: HDR + Surround Preferred', '(?i)^(?=.*\b576p\b)(?!.*\b(?:480p|720p|1080p|2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision))(?=.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', '576p-only preference for rare lower-resolution HDR/surround releases. It stays isolated from 480p, 720p, 1080p, and 4K formats.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: HDR + Surround Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: HDR + Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('576p: Efficient Encode Bonus', '(?i)^(?=.*\b576p\b)(?!.*\b(?:480p|720p|1080p|2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b).*$', '576p-only efficient-codec bonus for archive/catalog releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: Efficient Encode Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('576p: BluRay Preferred', '(?i)^(?=.*\b576p\b)(?!.*\b(?:480p|720p|1080p|2160p|4k)\b)(?=.*\b(?:blu[ ._-]?ray|bluray)\b).*$', '576p-only BluRay source bonus for PAL/576p-style archive releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('576p: WEB-DL Preferred', '(?i)^(?=.*\b576p\b)(?!.*\b(?:480p|720p|1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', '576p-only WEB-DL source bonus for lower-resolution catalog fallbacks.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('576p: WEBRip Source', '(?i)^(?=.*\b576p\b)(?!.*\b(?:480p|720p|1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', '576p-only WEBRip source detector for archive/catalog scoring.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: WEBRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('576p: BDRip Source', '(?i)^(?=.*\b576p\b)(?!.*\b(?:480p|720p|1080p|2160p|4k)\b)(?=.*\b(?:bd[ ._-]?rip|bdrip)\b).*$', '576p-only BDRip source detector for archive/catalog scoring.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('576p: BDRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('480p: HDR + Surround Preferred', '(?i)^(?=.*\b480p\b)(?!.*\b(?:576p|720p|1080p|2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision))(?=.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', '480p-only preference for rare low-resolution HDR/surround releases. Mostly useful for catalog scoring and remains isolated from higher resolutions.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: HDR + Surround Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: HDR + Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('480p: Efficient Encode Bonus', '(?i)^(?=.*\b480p\b)(?!.*\b(?:576p|720p|1080p|2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b).*$', '480p-only efficient-codec bonus for archive/catalog releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: Efficient Encode Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('480p: BluRay Preferred', '(?i)^(?=.*\b480p\b)(?!.*\b(?:576p|720p|1080p|2160p|4k)\b)(?=.*\b(?:blu[ ._-]?ray|bluray)\b).*$', '480p-only BluRay source bonus for older catalog or archive releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('480p: WEB-DL Preferred', '(?i)^(?=.*\b480p\b)(?!.*\b(?:576p|720p|1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', '480p-only WEB-DL source bonus for low-resolution catalog fallbacks.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('480p: WEBRip Source', '(?i)^(?=.*\b480p\b)(?!.*\b(?:576p|720p|1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', '480p-only WEBRip source detector for relaxed fallback scoring.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: WEBRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('480p: BDRip Source', '(?i)^(?=.*\b480p\b)(?!.*\b(?:576p|720p|1080p|2160p|4k)\b)(?=.*\b(?:bd[ ._-]?rip|bdrip)\b).*$', '480p-only BDRip source detector for relaxed fallback scoring.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('480p: BDRip Source', 'Smart Plex');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: Block x264-H264', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:avc|[xh][ ._-]?264)\b).*$', 'Heavy negative score for 4K or 2160p releases encoded as x264, H.264, or AVC. 4K should use a more efficient codec like HEVC, AV1, or VVC.');
