INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: HDR + Surround Preferred', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision))(?=.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', 'Positive compact-4K rule used by the 1080p-2160p profiles: rewards 4K releases only when they are efficient-codec, HDR/Dolby Vision, and have surround audio markers.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: HDR + Surround Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: HDR + Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: Efficient Encode Bonus', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:av1|vvc|h[ ._-]?266|x[ ._-]?266|hevc|h[ ._-]?265|x[ ._-]?265)\b).*$', 'Rewards 4K releases that also use an efficient codec such as HEVC, x265, AV1, H.266, x266, or VVC.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: Efficient Encode Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: Efficient Encode Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: UHD BluRay Preferred', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:uhd[ ._-]?blu[ ._-]?ray|uhd[ ._-]?bluray|blu[ ._-]?ray|bluray)\b).*$', 'Rewards 4K UHD BluRay or 4K BluRay source tags. Used to prefer cleaner 4K disc-sourced encodes when the file still fits the space-balanced rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: UHD BluRay Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: UHD BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: WEB-DL Preferred', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', 'Rewards 4K WEB-DL source tags. Useful for compact, clean 2160p HDR releases that are often smaller than BluRay-derived encodes.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: WEB-DL Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Movie Source: Block WEBRip', '(?i)\b(?:web[ ._-]?rip|webrip)\b', 'Legacy generic WEBRip detector kept for cleanup/compatibility. Current curated profiles use resolution-specific WEBRip source formats instead, so 1080p/720p/576p/480p/4K handling stays separate.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block WEBRip', 'Blocking');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block WEBRip', 'Movies');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Movie Source: Block BDRip', '(?i)\b(?:bd[ ._-]?rip|bdrip)\b', 'Legacy generic BDRip detector kept for cleanup/compatibility. Current curated profiles use resolution-specific BDRip source formats instead, so BDRip scoring can be strict for smart profiles and relaxed for catalog profiles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block BDRip', 'Blocking');
