INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Source: Block WEBRip', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', 'Hard reject for 4K WEBRip releases. The curated 4K lane should only keep clean WEB-DL or UHD BluRay style sources.');
