INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Gate: Block Missing 5.1+ Surround', '(?i)^(?=.*\b(?:2160p|4k)\b)(?!.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', 'Dedicated 4K profile gate: heavy negative score for 4K releases that do not show 5.1/6.1/7.1 or a known surround-capable codec marker.');
