INSERT OR REPLACE INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment) VALUES ('Alex_C.T - 4K Plex Movies', 'Manual 4K movie profile for users who explicitly want the most curated 2160p version. Profilarr ladder displays top-to-bottom as Bluray-2160p then WEBDL-2160p, while scoring prefers efficient HDR/Dolby Vision encodes, strong audio, language, and clean 4K sources. Remux, weak 4K rips, SDR 4K, 4K x264, 4K AAC-only, and 4K without 5.1+ surround are blocked or heavily penalized. Target rip quality: 10/10.', 1, 1100, 13000, 125);
